import org.springframework.boot.SpringApplication;
import org.springframework.boot.autoconfigure.SpringBootApplication;
import org.springframework.context.annotation.Bean;
import org.elasticsearch.client.RestHighLevelClient;
import org.elasticsearch.client.RestClient;
import org.elasticsearch.client.RestClientBuilder;
import org.elasticsearch.client.RequestOptions;
import org.elasticsearch.action.index.IndexRequest;
import org.elasticsearch.action.search.SearchRequest;
import org.elasticsearch.action.search.SearchResponse;
import org.elasticsearch.index.query.QueryBuilders;
import org.elasticsearch.search.builder.SearchSourceBuilder;
import org.elasticsearch.search.aggregations.AggregationBuilders;
import org.elasticsearch.search.aggregations.bucket.terms.TermsAggregationBuilder;
import org.elasticsearch.common.xcontent.XContentType;
import org.springframework.web.bind.annotation.*;

import java.io.IOException;
import java.util.Map;

@SpringBootApplication
public class ProductSearchApplication {

    public static void main(String[] args) {
        SpringApplication.run(ProductSearchApplication.class, args);
    }

    @Bean
    public RestHighLevelClient client() {
        RestClientBuilder builder = RestClient.builder(new HttpHost("localhost", 9200, "http"));
        return new RestHighLevelClient(builder);
    }
}

@RestController
@RequestMapping("/products")
class ProductController {

    private final RestHighLevelClient client;

    public ProductController(RestHighLevelClient client) {
        this.client = client;
    }

    @PostMapping("/index")
    public String indexProduct(@RequestBody Map<String, Object> product) throws IOException {
        IndexRequest request = new IndexRequest("products").source(product, XContentType.JSON);
        client.index(request, RequestOptions.DEFAULT);
        return "Product indexed successfully";
    }

    @GetMapping("/search")
    public SearchResponse searchProducts(@RequestParam String query) throws IOException {
        SearchSourceBuilder sourceBuilder = new SearchSourceBuilder();
        sourceBuilder.query(QueryBuilders.multiMatchQuery(query, "name", "description"));
        SearchRequest searchRequest = new SearchRequest("products").source(sourceBuilder);
        return client.search(searchRequest, RequestOptions.DEFAULT);
    }

    @GetMapping("/facets")
    public SearchResponse getFacets(@RequestParam String field) throws IOException {
        TermsAggregationBuilder aggregation = AggregationBuilders.terms("facet").field(field);
        SearchSourceBuilder sourceBuilder = new SearchSourceBuilder();
        sourceBuilder.aggregation(aggregation);
        SearchRequest searchRequest = new SearchRequest("products").source(sourceBuilder);
        return client.search(searchRequest, RequestOptions.DEFAULT);
    }
}